package app;

import io.micrometer.core.instrument.MeterRegistry;
import io.micrometer.core.instrument.Timer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Component;

// logs: SLF4J + logback-json → one JSON line per event
// metrics: Micrometer auto-exposes GET /actuator/prometheus
// traces: add micrometer-tracing-bridge-otel for spans
@Component
public class Observability {
  public static final Logger log = LoggerFactory.getLogger("app");
  public final Timer httpDuration;
  public Observability(MeterRegistry reg) {
    this.httpDuration = Timer.builder("http_request_duration_seconds")
        .description("request duration").register(reg);
  }
}

package app;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.web.SecurityFilterChain;

// Spring Security resource server verifies the JWT against your OIDC issuer.
// application.yml:
//   spring.security.oauth2.resourceserver.jwt.issuer-uri: ${OIDC_ISSUER}
@Configuration
public class SecurityConfig {
  @Bean
  SecurityFilterChain chain(HttpSecurity http) throws Exception {
    http.authorizeHttpRequests(a -> a
            .requestMatchers("/health", "/actuator/**").permitAll()
            .anyRequest().authenticated())
        .oauth2ResourceServer(o -> o.jwt(j -> {}));
    return http.build();
  }
}

