import com.auth0.jwk.JwkProviderBuilder
import io.ktor.server.application.*
import io.ktor.server.auth.*
import io.ktor.server.auth.jwt.*
import java.net.URI
import java.util.concurrent.TimeUnit

// Verifies the bearer token against your OIDC JWKS endpoint.
fun Application.installAuth() {
    val issuer = System.getenv("OIDC_ISSUER")
    val audience = System.getenv("OIDC_AUDIENCE")
    val jwks = JwkProviderBuilder(URI(System.getenv("OIDC_JWKS_URL")).toURL())
        .cached(10, 24, TimeUnit.HOURS).build()
    install(Authentication) {
        jwt {
            verifier(jwks, issuer)
            validate { c -> if (c.payload.audience.contains(audience)) JWTPrincipal(c.payload) else null }
        }
    }
}

