use jsonwebtoken::{decode, decode_header, jwk::JwkSet, Algorithm, DecodingKey, Validation};
use serde::Deserialize;

#[derive(Deserialize)]
pub struct Claims { pub sub: String, pub exp: usize }

// Verifies a bearer token against your OIDC JWKS (fetch + cache the set at startup).
pub fn verify(token: &str, jwks: &JwkSet, audience: &str, issuer: &str) -> Result<Claims, String> {
    let kid = decode_header(token).map_err(|e| e.to_string())?.kid.ok_or("no kid")?;
    let jwk = jwks.find(&kid).ok_or("unknown key")?;
    let key = DecodingKey::from_jwk(jwk).map_err(|e| e.to_string())?;
    let mut v = Validation::new(Algorithm::RS256);
    v.set_audience(&[audience]);
    v.set_issuer(&[issuer]);
    decode::<Claims>(token, &key, &v).map(|d| d.claims).map_err(|e| e.to_string())
}

