import Vapor
import Metrics
import Prometheus

// logs: Vapor's Logger emits structured output
// metrics: swift-prometheus backs swift-metrics, scraped at GET /metrics
public func bootstrapObservability(_ app: Application) {
    let prom = PrometheusCollectorRegistry()
    MetricsSystem.bootstrap(PrometheusMetricsFactory(registry: prom))
    app.get("metrics") { _ -> String in
        var buf = [UInt8]()
        prom.emit(into: &buf)
        return String(decoding: buf, as: UTF8.self)
    }
}

import Vapor
import JWT

// Verifies the bearer token against your OIDC keys (load the JWKS at startup).
struct UserClaims: JWTPayload {
    let sub: SubjectClaim
    let aud: AudienceClaim
    let exp: ExpirationClaim
    func verify(using signer: JWTSigner) throws { try exp.verifyNotExpired() }
}

struct RequireUser: AsyncMiddleware {
    func respond(to req: Request, chainingTo next: AsyncResponder) async throws -> Response {
        let claims = try req.jwt.verify(as: UserClaims.self)
        req.auth.login(claims)
        return try await next.respond(to: req)
    }
}

