using OpenTelemetry.Metrics;
using OpenTelemetry.Trace;
using Serilog;

// logs: Serilog JSON to stdout; metrics + traces: OpenTelemetry → Prometheus /metrics
public static class Observability
{
    public static void AddObservability(this WebApplicationBuilder b)
    {
        b.Host.UseSerilog((_, cfg) =>
            cfg.WriteTo.Console(new Serilog.Formatting.Json.JsonFormatter()));
        b.Services.AddOpenTelemetry()
            .WithMetrics(m => m.AddAspNetCoreInstrumentation().AddPrometheusExporter())
            .WithTracing(t => t.AddAspNetCoreInstrumentation());
    }
}

using Microsoft.AspNetCore.Authentication.JwtBearer;

// Verifies the caller's JWT against your OIDC issuer on every protected endpoint.
public static class Auth
{
    public static void AddJwtAuth(this WebApplicationBuilder b)
    {
        b.Services.AddAuthentication(JwtBearerDefaults.AuthenticationScheme)
            .AddJwtBearer(o =>
            {
                o.Authority = Environment.GetEnvironmentVariable("OIDC_ISSUER");
                o.Audience = Environment.GetEnvironmentVariable("OIDC_AUDIENCE");
            });
        b.Services.AddAuthorization();
    }
}
